var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"이걸… 워치라고 하나요?","JPN":"これを……ウォッチって言うんですか？","ENG":"This is... called a Watch?","TWN":"這個……就是能量環嗎？"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래. 카운터라면 하나씩은 가지고 있는 물건이다.","JPN":"うん。カウンターならみんな持ってる代物だ。","ENG":"Yes. It's something all Counters carry around.","TWN":"沒錯，制裁者的話都會有一件這樣的東西。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"신기하네요. 방금 훈련 때 제가 특별한 능력을 쓴 것도 이 워치 덕분이군요!","JPN":"不思議です。さっきの訓練で私が特別な能力を使えたのも、このウォッチのおかげなんですね！","ENG":"How fascinating. So it's thanks to this Watch that I was able to use my special ability during training!","TWN":"真神奇。剛才訓練時我能使用特殊能力也是多虧了它！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"맞아. 힐데가 널 각성시킨답시고 달려들었을 때, 네가 보이지 않는 벽으로 그 녀석을 가뒀지.","JPN":"うん。ヒルデがあなたを覚醒させると飛び掛かった瞬間、あなたは目に見えない壁であいつを閉じ込めた。","ENG":"That's right. When Hilde attacked you to awaken you, you trapped her inside an invisible wall.","TWN":"沒錯。希爾德幫你覺醒的時候，你用看不見的牆壁把她困住了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"unit_laugh"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그게 네 카운터로서의 능력이다.","JPN":"それがあなたのカウンターとしての能力だよ。","ENG":"That is your Counter ability.","TWN":"那就是你作為制裁者的能力。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그건… 일부러 그런 게 아니었어요.","JPN":"あれは……わざとじゃないんです。","ENG":"I... didn't do it on purpose.","TWN":"那個……我不是故意的。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"머뭇대면 정말로 죽을 것 같아서 저도 모르게….","JPN":"迷ったら、本当に死ぬと思って……つい……","ENG":"I thought I'd die if I hesitated, and...","TWN":"但是猶豫不決的話，感覺真的會被師父殺掉，所以才不由自主地……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아하하, 좀 더 자랑스러워해도 돼.","JPN":"あはは、もっと誇らしく思っていい。","ENG":"Ah hah hah. You should be proud of yourself.","TWN":"哈哈哈，這點已經夠其他人吹噓一輩子了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그 발키리 녀석을 그렇게 꼼짝 못하게 만드는 존재는 세상에 그리 많지 않거든.","JPN":"あのヴァルキリーにあんなことできるなんて、この世に何人もいないんだから。","ENG":"There aren't many beings who can immobilize that Valkyrie like you have.","TWN":"能夠讓那個女武神動彈不得的存在，在這個世界上可不多見。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그때의 힐데님은 무서웠지만… 덕분에 저도 능력이란 걸 쓸 수 있게 됐어요.","JPN":"あの時のヒルデさんは怖かったけど……おかげで私も能力というものが使えるようになりました。","ENG":"I was afraid of Miss Hilde back then... But thanks to her, I'm now able to use this ability.","TWN":"雖然希爾德師父衝過來的時候很可怕……但多虧了她，我也能使用能力了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"이 힘으로 관리국에 도움이 될 수 있다고 생각하니 기쁘네요!","JPN":"これで管理局の役に立てると思うと、嬉しいです！","ENG":"I'm glad that I can use this power to help the Administration!","TWN":"一想到能用這股力量幫助管理局，我就很開心呢！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"하지만 조심해. 카운터의 힘은 네가 가진 가능성을 소모하니까.","JPN":"でも気をつけて。カウンターの力は、あなたの持つ可能性を消耗するから。","ENG":"But be careful. A Counter's power consumes the possibilities you have.","TWN":"但是要小心。制裁者的力量會消耗你的可能性。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"가능성…?","JPN":"可能性……？","ENG":"Possibilities...?","TWN":"可能性……？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"이걸 전부 쓰면 어떻게 되죠?","JPN":"それを使い切ってしまったら、どうなるんですか？","ENG":"What happens if I use it all up?","TWN":"如果把它全部用掉會怎麼樣？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭐, 이터니움을 계속 공급 받을 수 있는 환경이라면 큰 문제는 없을 거야.","JPN":"まあ、エタニウムを供給してもらえる環境なら大した問題はないと思う。","ENG":"Well, it won't be a problem if you're in an environment where Eternium is continuously supplied.","TWN":"嗯，如果有永恆之金持續供應，應該沒什麼大問題。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"하지만, 네가 가진 워치의 바늘이 0을 가리킬 때까지 힘을 쓰게 된다면…","JPN":"でも、あなたのウォッチの針が0を指すまで力を使い続けてしまうと……","ENG":"However, if you use your powers until the hand on your Watch points to 0...","TWN":"但如果你用盡最後一絲力量，直到指針指到了0……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…침식체와 다름없는 존재로 변하고 말 테니까.","JPN":"……侵食体と同じ存在に、変わり果ててしまう。","ENG":"...you'll turn into something no different from a C.O.","TWN":"……就會變成和侵蝕體一樣的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그 말이… 정말인가요?","JPN":"それは……本当ですか？","ENG":"Is that... true?","TWN":"你說的……是真的嗎？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"하지만… 우리가 찾은 워치의 바늘은 이미…","JPN":"でも……私たちが見つけたウォッチの針は、すでに……","ENG":"But... the hand on the Watch we found was already at...","TWN":"但是……這塊能量環的指針已經……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아니야. 어머니를 어서 찾으러 가죠! 아직 늦지 않았을 거예요!","JPN":"違う……お母さんを探しに行きましょう！　まだ間に合うはずです！","ENG":"No. Let's go find Mother! It might not be too late!","TWN":"不要！我們快去找媽媽吧！還不算太晚！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"따라와.","JPN":"ついてきて。","ENG":"Follow me.","TWN":"跟我來。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여긴? 안뜰로 향하는 문이잖아요?","JPN":"ここは……？　中庭に入る扉じゃないですか。","ENG":"Isn't this... the door to the inner yard?","TWN":"這裡是？通往內院的門嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"지금부터 이 워치를 이용해서 저 문을 열어봐라.","JPN":"今からこのウォッチを使って、あの扉を開けてみて。","ENG":"Now, use the Watch to open the door.","TWN":"現在用這個能量環去打開那扇門吧。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 어머니가 아닌 걸요. 어머니의 워치가 있어도 능력은 쓰지 못할 거예요.","JPN":"でも私はお母さんじゃないです。お母さんのウォッチがあっても、能力は使えません。","ENG":"But I'm not my mother. So, even with her Watch, I won't be able to use her ability.","TWN":"我不是媽媽。即使有媽媽的能量環，也不能使用她的能力……"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};